// Generate a minimal 48x48 PNG with 'Eva' text \(solid purple square\)
// This creates a valid PNG with a single-color 48x48 image
const fs = require\('fs'\);

// Minimal 48x48 PNG - solid #6366F1 purple
// Pre-generated base64 of a simple purple square
const width = 48, height = 48;

// Build raw RGBA pixel data
const pixels = Buffer.alloc\(width * height * 4\);
const r = 0x63, g = 0x66, b = 0xF1, a = 0xFF;
for \(let i = 0; i < width * height; i++\) {
  pixels[i * 4] = r;
  pixels[i * 4 + 1] = g;
  pixels[i * 4 + 2] = b;
  pixels[i * 4 + 3] = a;
}

// Simple uncompressed PNG
const zlib = require\('zlib'\);

function crc32\(buf\) {
  let crc = 0xFFFFFFFF;
  const table = new Int32Array\(256\);
  for \(let i = 0; i < 256; i++\) {
    let c = i;
    for \(let j = 0; j < 8; j++\) c = c & 1 ? 0xEDB88320 ^ \(c >>> 1\) : c >>> 1;
    table[i] = c;
  }
  for \(let i = 0; i < buf.length; i++\) crc = table[\(crc ^ buf[i]\) & 0xFF] ^ \(crc >>> 8\);
  return \(crc ^ 0xFFFFFFFF\) >>> 0;
}

function chunk\(type, data\) {
  const len = Buffer.alloc\(4\);
  len.writeUInt32BE\(data.length\);
  const typeData = Buffer.concat\([Buffer.from\(type\), data]\);
  const crc = Buffer.alloc\(4\);
  crc.writeUInt32BE\(crc32\(typeData\)\);
  return Buffer.concat\([len, typeData, crc]\);
}

// IHDR
const ihdr = Buffer.alloc\(13\);
ihdr.writeUInt32BE\(width, 0\);
ihdr.writeUInt32BE\(height, 4\);
ihdr[8] = 8; // bit depth
ihdr[9] = 6; // RGBA
ihdr[10] = 0; ihdr[11] = 0; ihdr[12] = 0;

// IDAT - raw image data with filter bytes
const rawData = Buffer.alloc\(height * \(1 + width * 4\)\);
for \(let y = 0; y < height; y++\) {
  rawData[y * \(1 + width * 4\)] = 0; // filter: none
  pixels.copy\(rawData, y * \(1 + width * 4\) + 1, y * width * 4, \(y + 1\) * width * 4\);
}
const compressed = zlib.deflateSync\(rawData\);

const png = Buffer.concat\([
  Buffer.from\([137, 80, 78, 71, 13, 10, 26, 10]\), // PNG signature
  chunk\('IHDR', ihdr\),
  chunk\('IDAT', compressed\),
  chunk\('IEND', Buffer.alloc\(0\)\),
]\);

fs.writeFileSync\('C:/dev/ycode-fork/ycode/extensions/eva-css/icons/icon48.png', png\);
console.log\('Created icon48.png \(' + png.length + ' bytes\)'\);
")

